mapper.select:
SELECT a.* , b.user_nm FROM t_login_log a LEFT JOIN t_user_info b ON a.user_id = b.user_id WHERE 1 = 1
AND DATE_FORMAT(login_de, '%Y%m%d') BETWEEN #{srchBeginDt} AND #{srchEndDt}
AND a.login_id LIKE CONCAT('%', #{loginId}, '%')
AND b.user_nm LIKE CONCAT('%', #{userNm}, '%')
ORDER BY log_seq DESC LIMIT #{firstIndex}, #{row}

